sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var connectorType = request.pathParams.connectorType;
    var webhookId = request.pathParams.webhookId;
    var body = request.body.data;
    var headers = {};

    // Extract headers
    var headerNames = request.getHeaderNames();
    for (var i = 0; i < headerNames.size(); i++) {
        var name = headerNames.get(i);
        headers[name] = request.getHeader(name);
    }

    var engine = new x_146833_idpkiro.IDPIntegrationEngine();
    var result = engine.processWebhook(connectorType, body, headers);

    response.setStatus(result.success ? 200 : 400);
    response.setBody(result);
})(request, response);
